/**
 * COUNT(*) coverage for the native LMDB aggregate path: the wildcard count must compile natively (observable through
 * {@link LmdbNativeAggregateCompiler#COMPILED}) and count solution rows including join multiplicity, across the plain,
 * grouped, factorized-tail and HAVING evaluation shapes. COUNT(DISTINCT *) counts distinct full rows, which the
 * id-based state cannot represent, so it must stay on the generic path while still returning correct results.
 */
public class LmdbNativeCountStarTest {

	private static final String EX = "http://example.com/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI person = vf.createIRI(EX, "Person");
			IRI knows = vf.createIRI(EX, "knows");
			IRI nick = vf.createIRI(EX, "nick");
			IRI hub = vf.createIRI(EX, "Hub");
			IRI e1 = vf.createIRI(EX, "e1");
			IRI e2 = vf.createIRI(EX, "e2");
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			IRI p3 = vf.createIRI(EX, "p3");
			IRI h1 = vf.createIRI(EX, "h1");
			conn.add(p1, RDF.TYPE, person);
			conn.add(p2, RDF.TYPE, person);
			conn.add(p3, RDF.TYPE, person);
			conn.add(p1, knows, p2);
			conn.add(p1, knows, p3);
			conn.add(p2, knows, p3);
			conn.add(p3, knows, vf.createIRI(EX, "bot"));
			conn.add(p2, nick, vf.createLiteral("n2"));
			conn.add(h1, RDF.TYPE, hub);
			conn.add(h1, e1, vf.createIRI(EX, "x1"));
			conn.add(h1, e1, vf.createIRI(EX, "x2"));
			conn.add(h1, e1, vf.createIRI(EX, "x3"));
			conn.add(h1, e2, vf.createIRI(EX, "y1"));
			conn.add(h1, e2, vf.createIRI(EX, "y2"));
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	@Test
	public void countStarOverSingleScan() {
		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT (COUNT(*) AS ?c) WHERE { ?s ?p ?o }").evaluate());
			assertThat(result).hasSize(1);
			assertThat(((Literal) result.get(0).getValue("c")).longValue()).isEqualTo(14L);
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("COUNT(*) over a single scan must compile natively")
				.isGreaterThan(compiledBefore);
	}

	@Test
	public void countStarOverJoin() {
		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT (COUNT(*) AS ?c) WHERE { ?s a <" + EX + "Person> . ?s <" + EX + "knows> ?o . }")
					.evaluate());
			assertThat(((Literal) result.get(0).getValue("c")).longValue()).isEqualTo(4L);
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("COUNT(*) over a join must compile natively")
				.isGreaterThan(compiledBefore);
	}

	@Test
	public void groupedCountStar() {
		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT ?s (COUNT(*) AS ?c) WHERE { ?s a <" + EX + "Person> . ?s <" + EX + "knows> ?o . }"
							+ " GROUP BY ?s")
					.evaluate());
			Map<String, Long> counts = new HashMap<>();
			for (BindingSet bs : result) {
				counts.put(bs.getValue("s").stringValue(), ((Literal) bs.getValue("c")).longValue());
			}
			assertThat(counts).isEqualTo(Map.of(EX + "p1", 2L, EX + "p2", 1L, EX + "p3", 1L));
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("grouped COUNT(*) must compile natively")
				.isGreaterThan(compiledBefore);
	}

	@Test
	public void countStarCountsFactorizedMultiplicityProduct() {
		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			// two independent fanout branches under one hub: COUNT(*) is the 3x2 product
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT (COUNT(*) AS ?c) WHERE { ?h a <" + EX + "Hub> ."
							+ " ?h <" + EX + "e1> ?x . ?h <" + EX + "e2> ?y . }")
					.evaluate());
			assertThat(((Literal) result.get(0).getValue("c")).longValue()).isEqualTo(6L);
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("COUNT(*) over a star join must compile natively")
				.isGreaterThan(compiledBefore);
	}

	@Test
	public void countStarWithHaving() {
		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT ?s (COUNT(*) AS ?c) WHERE { ?s a <" + EX + "Person> . ?s <" + EX + "knows> ?o . }"
							+ " GROUP BY ?s HAVING(COUNT(*) > 1)")
					.evaluate());
			assertThat(result).hasSize(1);
			assertThat(result.get(0).getValue("s").stringValue()).isEqualTo(EX + "p1");
			assertThat(((Literal) result.get(0).getValue("c")).longValue()).isEqualTo(2L);
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("COUNT(*) with HAVING must compile natively")
				.isGreaterThan(compiledBefore);
	}

	@Test
	public void countStarMixedWithCountVarOverOptional() {
		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT ?s (COUNT(*) AS ?c) (COUNT(?nick) AS ?n) WHERE {"
							+ " ?s a <" + EX + "Person> . ?s <" + EX + "knows> ?o ."
							+ " OPTIONAL { ?o <" + EX + "nick> ?nick } } GROUP BY ?s")
					.evaluate());
			Map<String, long[]> counts = new HashMap<>();
			for (BindingSet bs : result) {
				counts.put(bs.getValue("s").stringValue(), new long[] {
						((Literal) bs.getValue("c")).longValue(),
						((Literal) bs.getValue("n")).longValue() });
			}
			assertThat(counts.get(EX + "p1")).containsExactly(2L, 1L);
			assertThat(counts.get(EX + "p2")).containsExactly(1L, 0L);
			assertThat(counts.get(EX + "p3")).containsExactly(1L, 0L);
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("COUNT(*) mixed with COUNT(?var) over OPTIONAL must compile natively")
				.isGreaterThan(compiledBefore);
	}

	@Test
	public void countStarOverEmptyMatchIsZero() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT (COUNT(*) AS ?c) WHERE { ?s a <" + EX + "Ghost> }").evaluate());
			assertThat(result).hasSize(1);
			assertThat(((Literal) result.get(0).getValue("c")).longValue()).isEqualTo(0L);
		}
	}

	@Test
	public void countDistinctStarStaysOnGenericPath() {
		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT (COUNT(DISTINCT *) AS ?c) WHERE { ?s a <" + EX + "Person> . ?s <" + EX + "knows> ?o . }")
					.evaluate());
			assertThat(((Literal) result.get(0).getValue("c")).longValue()).isEqualTo(4L);
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("COUNT(DISTINCT *) must stay on the generic path")
				.isEqualTo(compiledBefore);
	}
}
